mapper.select:
SELECT , COALESCE(rs.used_area, 0) AS used_area, COALESCE(rs.total_count, 0) AS total_count, COALESCE(rs.rented_count, 0) AS rented_count, COALESCE(rs.vacant_count, 0) AS vacant_count, COALESCE(rs.reserved_count, 0) AS reserved_count, COALESCE(rs.renovating_count, 0) AS renovating_count, COALESCE(rs.disabled_count, 0) AS disabled_count FROM ics_floor f LEFT JOIN ics_building b ON b.id = f.building_id LEFT JOIN ics_park p ON p.id = f.park_id LEFT JOIN ( SELECT building_id, floor, COUNT(1) AS total_count, SUM(COALESCE(area, 0)) AS used_area, SUM(CASE WHEN status = '1' THEN 1 ELSE 0 END) AS rented_count, SUM(CASE WHEN status = '0' THEN 1 ELSE 0 END) AS vacant_count, SUM(CASE WHEN status = '2' THEN 1 ELSE 0 END) AS reserved_count, SUM(CASE WHEN status = '3' THEN 1 ELSE 0 END) AS renovating_count, SUM(CASE WHEN status = '4' THEN 1 ELSE 0 END) AS disabled_count FROM ics_room GROUP BY building_id, floor ) rs ON rs.building_id = f.building_id AND rs.floor = f.floor_no
AND f.id = #{floor.id} AND f.park_id = #{floor.parkId} AND f.building_id = #{floor.buildingId} AND f.floor_no = #{floor.floorNo} AND f.status = #{floor.status}
ORDER BY p.name ASC, b.name ASC, f.floor_no DESC

SELECT COUNT(1)
FROM ics_room
WHERE building_id = #{buildingId}
  AND floor = #{floorNo}
